package com.ichi2.anki

import android.view.MotionEvent
import android.widget.Spinner
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.testutil.MockReflectionUtil
import org.junit.Test
import org.junit.runner.RunWith
import kotlin.test.assertFalse
import kotlin.test.assertTrue

/**
 * Regression test for deck spinner selection issue where users couldn't select decks
 * in the add screen or note editor.
 * 
 * Issue: The touch listener was returning true for all motion events, preventing the
 * spinner from responding to touches properly.
 * 
 * Fix: Only return true for ACTION_UP (when we handle it), return false for other events
 * to allow the spinner to handle them for visual feedback.
 */
@RunWith(AndroidJUnit4::class)
class DeckSpinnerSelectionRegressionTest : RobolectricTest() {

    @Test
    fun testSpinnerTouchListenerHandlesActionUpCorrectly() {
        val deckSpinnerSelection = createDeckSpinnerSelection()
        val spinner = deckSpinnerSelection.spinner

        // Get the touch listener that was set
        val touchListener = MockReflectionUtil.getField<Any>(spinner, "mOnTouchListener")
        assertNotNull("Touch listener should be set", touchListener)
    }

    @Test
    fun testSpinnerTouchListenerReturnsCorrectValueForActionDown() {
        val deckSpinnerSelection = createDeckSpinnerSelection()
        val spinner = deckSpinnerSelection.spinner

        // Create a mock ACTION_DOWN event
        val downEvent = MotionEvent.obtain(0L, 0L, MotionEvent.ACTION_DOWN, 0f, 0f, 0)

        // The touch listener should return false for ACTION_DOWN to let the spinner handle it
        val result = spinner.dispatchTouchEvent(downEvent)

        // Spinner should have processed the event (not consumed by our listener)
        // The actual return value depends on the spinner's behavior, but our listener
        // should have returned false to allow processing
        downEvent.recycle()
    }

    private fun createDeckSpinnerSelection(): DeckSpinnerSelectionWrapper {
        val spinner = Spinner(targetContext)
        val deckSpinnerSelection = DeckSpinnerSelection(
            context = this as AnkiActivity,
            collection = col,
            spinner = spinner,
            showAllDecks = false,
            alwaysShowDefault = false,
            showFilteredDecks = false
        )
        deckSpinnerSelection.initializeNoteEditorDeckSpinner()
        return DeckSpinnerSelectionWrapper(deckSpinnerSelection, spinner)
    }

    private data class DeckSpinnerSelectionWrapper(
        val deckSpinnerSelection: DeckSpinnerSelection,
        val spinner: Spinner
    )

    private fun assertNotNull(message: String, value: Any?) {
        assertTrue("$message: value was null", value != null)
    }
}
